#' Validate Spec File Against Schema
#'
#' Checks that a spec file conforms to the specverse JSON schema for its version.
#'
#' @param spec_file Path to the spec file to validate
#' @param verbose Logical, whether to print validation details
#'
#' @return Logical, TRUE if valid, FALSE otherwise
#' @export
#'
#' @examples
#' \dontrun{
#' sv_validate("spec/my_function.v1.json")
#' }
sv_validate <- function(spec_file, verbose = TRUE) {
  if (!fs::file_exists(spec_file)) {
    cli::cli_abort("Spec file does not exist: {spec_file}")
  }

  # Read spec file
  tryCatch({
    spec_data <- jsonlite::read_json(spec_file)
  }, error = function(e) {
    if (verbose) cli::cli_alert_danger("Invalid JSON in {spec_file}: {e$message}")
    return(FALSE)
  })

  # Check for required schema version field
  if (is.null(spec_data$specverse_schema)) {
    if (verbose) cli::cli_alert_danger("Missing 'specverse_schema' field in {spec_file}")
    return(FALSE)
  }

  schema_version <- spec_data$specverse_schema

  # Validate based on schema version
  if (schema_version == "v0.1") {
    result <- .validate_v01_schema(spec_data, spec_file, verbose)
  } else {
    if (verbose) cli::cli_alert_danger("Unsupported schema version: {schema_version}")
    return(FALSE)
  }

  if (result && verbose) {
    cli::cli_alert_success("Spec file {spec_file} is valid (schema {schema_version})")
  }

  return(result)
}

# Internal function to validate v0.1 schema
.validate_v01_schema <- function(spec_data, spec_file, verbose) {
  required_fields <- c("specverse_schema", "name", "function_name", "inputs", "output")

  missing_fields <- setdiff(required_fields, names(spec_data))

  if (length(missing_fields) > 0) {
    if (verbose) {
      cli::cli_alert_danger("Missing required fields in {spec_file}: {paste(missing_fields, collapse = ', ')}")
    }
    return(FALSE)
  }

  # Additional validation rules for v0.1
  if (!is.character(spec_data$name) || length(spec_data$name) != 1) {
    if (verbose) cli::cli_alert_danger("Field 'name' must be a single character string")
    return(FALSE)
  }

  if (!is.character(spec_data$function_name) || length(spec_data$function_name) != 1) {
    if (verbose) cli::cli_alert_danger("Field 'function_name' must be a single character string")
    return(FALSE)
  }

  if (!is.list(spec_data$inputs)) {
    if (verbose) cli::cli_alert_danger("Field 'inputs' must be a list")
    return(FALSE)
  }

  return(TRUE)
}

