#' Check Cross-Language Parity
#'
#' Compares cached results across different language implementations to verify
#' they produce identical outputs for the same inputs.
#'
#' @param spec_dir Directory containing spec files (default: "spec")
#' @param cache_dir Directory containing cache files (default: "results/cache")
#' @param tolerance Numeric tolerance for floating point comparisons
#' @param verbose Logical, whether to print detailed results
#'
#' @return A data frame with parity check results
#' @export
#'
#' @examples
#' \dontrun{
#' # Check parity across all cached results
#' results <- sv_check()
#' 
#' # Check with custom tolerance
#' results <- sv_check(tolerance = 1e-10)
#' }
sv_check <- function(spec_dir = "spec", cache_dir = "results/cache", tolerance = 1e-12, verbose = TRUE) {

  # Validate directories exist
  if (!fs::dir_exists(spec_dir)) {
    cli::cli_abort("Spec directory does not exist: {spec_dir}")
  }

  if (!fs::dir_exists(cache_dir)) {
    cli::cli_abort("Cache directory does not exist: {cache_dir}")
  }

  # Check for cache files - refuse to run if empty (T-07)
  cache_files <- fs::dir_ls(cache_dir, recurse = TRUE, type = "file", glob = "*.json")

  if (length(cache_files) == 0) {
    cli::cli_abort(
      c("No cache files found in {cache_dir}",
        "i" = "Run language-specific tests first to generate cache files",
        "i" = "This prevents false-positive passes on fresh clones")
    )
  }

  # Get all spec files
  spec_files <- fs::dir_ls(spec_dir, glob = "*.json")

  if (length(spec_files) == 0) {
    cli::cli_warn("No spec files found in {spec_dir}")
    return(data.frame())
  }

  # Process each spec
  results <- list()

  for (spec_file in spec_files) {
    spec_name <- fs::path_ext_remove(fs::path_file(spec_file))
    spec_name <- sub("\\.v\\d+$", "", spec_name)  # Remove version suffix

    if (verbose) cli::cli_inform("Checking spec: {spec_name}")

    # Find matching cache files across all run_ids
    cache_pattern <- paste0("**/", spec_name, ".*.json")
    matching_caches <- fs::dir_ls(cache_dir, recurse = TRUE, glob = cache_pattern)

    if (length(matching_caches) < 2) {
      if (verbose) cli::cli_warn("Insufficient cache files for {spec_name} (found {length(matching_caches)}, need >= 2)")
      next
    }

    # Load spec for reference
    spec_data <- jsonlite::read_json(spec_file)

    # Load cache results
    cache_results <- list()
    for (cache_file in matching_caches) {
      lang <- .extract_language_from_cache_path(cache_file)
      cache_data <- jsonlite::read_json(cache_file)
      cache_results[[lang]] <- cache_data$output
    }

    # Compare results pairwise
    spec_results <- .compare_cache_results(spec_name, cache_results, tolerance, verbose)
    results <- c(results, list(spec_results))
  }

  # Combine all results
  if (length(results) > 0) {
    final_results <- do.call(rbind, results)
  } else {
    final_results <- data.frame(
      spec = character(0),
      lang1 = character(0),
      lang2 = character(0),
      status = character(0),
      max_diff = numeric(0)
    )
  }

  if (verbose) {
    .print_check_summary(final_results)
  }

  return(final_results)
}

# Extract language from cache file path
.extract_language_from_cache_path <- function(cache_path) {
  filename <- fs::path_file(cache_path)
  # Extract language from pattern: spec_name.LANG.json
  parts <- strsplit(filename, "\\.")[[1]]
  if (length(parts) >= 3) {
    return(parts[length(parts) - 1])  # Second to last part before .json
  }
  return("unknown")
}

# Compare cache results across languages
.compare_cache_results <- function(spec_name, cache_results, tolerance, verbose) {
  languages <- names(cache_results)
  results <- list()

  for (i in 1:(length(languages) - 1)) {
    for (j in (i + 1):length(languages)) {
      lang1 <- languages[i]
      lang2 <- languages[j]

      result1 <- cache_results[[lang1]]
      result2 <- cache_results[[lang2]]

      comparison <- .compare_outputs(result1, result2, tolerance)

      results[[length(results) + 1]] <- data.frame(
        spec = spec_name,
        lang1 = lang1,
        lang2 = lang2,
        status = comparison$status,
        max_diff = comparison$max_diff,
        stringsAsFactors = FALSE
      )

      if (verbose) {
        if (comparison$status == "PASS") {
          cli::cli_alert_success("{lang1} vs {lang2}: PASS (max_diff: {format(comparison$max_diff, scientific = TRUE)})")
        } else {
          cli::cli_alert_danger("{lang1} vs {lang2}: FAIL (max_diff: {format(comparison$max_diff, scientific = TRUE)})")
        }
      }
    }
  }

  do.call(rbind, results)
}

# Compare two outputs with tolerance
.compare_outputs <- function(output1, output2, tolerance) {
  tryCatch({
    if (is.numeric(output1) && is.numeric(output2)) {
      max_diff <- max(abs(output1 - output2), na.rm = TRUE)
      status <- if (max_diff <= tolerance) "PASS" else "FAIL"
    } else {
      # For non-numeric, use exact comparison
      exact_match <- identical(output1, output2)
      max_diff <- if (exact_match) 0 else Inf
      status <- if (exact_match) "PASS" else "FAIL"
    }

    list(status = status, max_diff = max_diff)
  }, error = function(e) {
    list(status = "ERROR", max_diff = Inf)
  })
}

# Print summary of check results
.print_check_summary <- function(results) {
  if (nrow(results) == 0) {
    cli::cli_alert_info("No comparisons performed")
    return()
  }

  n_pass <- sum(results$status == "PASS")
  n_fail <- sum(results$status == "FAIL")
  n_error <- sum(results$status == "ERROR")

  cli::cli_rule("Parity Check Summary")
  cli::cli_alert_success("PASS: {n_pass}")
  if (n_fail > 0) cli::cli_alert_danger("FAIL: {n_fail}")
  if (n_error > 0) cli::cli_alert_danger("ERROR: {n_error}")

  if (n_fail > 0 || n_error > 0) {
    cli::cli_alert_warning("Some checks failed - see results for details")
  } else {
    cli::cli_alert_success("All parity checks passed!")
  }
}

