    spec_file = Path(spec_dir) / f"{spec_name}.v1.json"
    with open(spec_file) as f:
        return json.load(f)

def write_cache(spec_name, result, language="python", cache_dir="results/cache"):
    """Write result to cache file"""
    run_id = hashlib.md5(str(time.time()).encode()).hexdigest()[:8]
    cache_path = Path(cache_dir) / run_id
    cache_path.mkdir(parents=True, exist_ok=True)

    cache_data = {
        "spec_name": spec_name,
        "language": language,
        "output": result,
        "timestamp": time.time()
    }

    cache_file = cache_path / f"{spec_name}.{language}.json"
    with open(cache_file, "w") as f:
        json.dump(cache_data, f, indent=2)

    return str(cache_file)
'

  helper_file <- fs::path(test_dir, "specverse_helper.py")
